/* ================================================================
 * 폰트 페이스 — CDN @import
 *
 * - SUIT Variable: brand 기본 family. `--font-sans`가 가리킴
 * - Pretendard Variable: SUIT 자매 family (dynamic-subset). `--font-pretendard`
 *
 * 별도 파일로 분리한 이유:
 * CSS 스펙상 @import는 다른 모든 rule보다 앞에 와야 한다.
 * tokens/theme/typography 같이 @theme·@utility를 담은 파일 안에 @import url(...)을
 * 두면 entry 합성 시 다른 rule 뒤에 위치할 수 있어 파서가 무효 처리한다.
 *
 * 따라서 이 파일은 사용자 앱의 entry CSS 최상단에 가장 먼저 import한다:
 *   @import '@transight-design/ui/styles/fonts.css';
 *   @import 'tailwindcss';
 *   ...
 *
 * 한쪽 family만 쓰고 싶은 앱은 이 파일을 entry에 넣지 않고 원하는 CDN URL만
 * 직접 import하면 된다 (디자인 시스템 default는 SUIT + Pretendard 둘 다 로드).
 * ================================================================ */

@import url('https://cdn.jsdelivr.net/gh/sunn-us/SUIT/fonts/variable/woff2/SUIT-Variable.css');
@import url('https://cdn.jsdelivr.net/gh/orioncactus/pretendard@v1.3.9/dist/web/variable/pretendardvariable-dynamic-subset.min.css');
